module async_reset_counter (
    input               reset_clk,
    input               rst,
    output reg [7:0]    count
);

    always @(posedge reset_clk or posedge rst) begin
        if (rst) begin
            count <= 8'b00000000;
        end else begin
            count <= count + 1;
        end
    end

endmodule
